import pandas as pd, numpy as np, torch, re
from torch.utils.data import Dataset, DataLoader
from transformers import AutoTokenizer, AutoModelForSequenceClassification
from torch.optim import AdamW
from sklearn.model_selection import train_test_split
from sklearn.metrics import classification_report, f1_score
from sklearn.utils.class_weight import compute_class_weight

device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
print(device)

"""- pandas, numpy → manipulation des données
- torch → deep learning (PyTorch)
- Dataset, DataLoader → gestion des données en batches
- transformers → modèles pré-entraînés (BERT, etc.)
- AdamW → optimiseur adapté aux transformers
- sklearn → séparation des données + évaluation
- re → nettoyage de texte (regex)

# **2. Préprocessing minimal (seulement  pour BERT)**

BERTweet a été entraîné avec ses propres conventions : @USER pour les mentions et HTTPURL pour les liens. Il faut respecter ce format sinon les tokens seront inconnus.
"""

def clean_for_bertweet(text):
    # Remplacements propres au format BERTweet
    text = re.sub(r'http\S+|www\S+', 'HTTPURL', text)  # URLs → HTTPURL
    text = re.sub(r'@\w+', '@USER', text)               # mentions → @USER
    text = re.sub(r'\s+', ' ', text).strip()
    return text

# Chargement
df = pd.read_csv("/content/hatespeech2.csv")
df["text_bert"] = df["tweet"].apply(clean_for_bertweet)

print(df["class"].value_counts())
print("\nExemple :")
print(df["text_bert"].iloc[0])

"""- Standardise le texte pour BERTweet (HTTPURL, @USER)
- Nettoie les espaces
- Applique le traitement à tout le dataset
- Vérifie la distribution des classes

 🥇 preprocessing est correct pour BERTweet, car ce modèle a été entraîné avec ces mêmes tokens (HTTPURL, @USER).

# **3. Train/Test split stratifié**
"""

X_train, X_test, y_train, y_test = train_test_split(
    df["text_bert"].values,
    df["class"].values,
    test_size=0.2,
    random_state=42,
    stratify=df["class"]    #Sans stratify, ton modèle peut être mal évalué si les classes sont déséquilibrées
)

print(f"Train : {len(X_train)} | Test : {len(X_test)}")

"""- séparer les données (80% / 20%)
- garder l’équilibre des classes (grâce à stratify)
- assurer la reproductibilité (random_state)

# **4. Tokenizer BERTweet**
"""

MODEL_NAME = "vinai/bertweet-base"

tokenizer = AutoTokenizer.from_pretrained(
    MODEL_NAME,
    use_fast=False,       # BERTweet nécessite le tokenizer lent
    normalization=True    # normalisation interne des tweets
)

# Test rapide
sample = tokenizer(
    "I hate this HTTPURL @USER",
    max_length=128,
    padding="max_length",
    truncation=True,
    return_tensors="pt"
)
print("Tokens exemple :", tokenizer.convert_ids_to_tokens(sample["input_ids"][0])[:15])

"""- Charge le tokenizer de BERTweet :
 Le tokenizer fait donc 2 choses :

1- Découper le texte
2- Transformer chaque token en un identifiant numérique (ID)

- Convertit le texte en format numérique
- Gère longueur, padding, troncature
- Vérifie visuellement les tokens

# **5 — TweetDataset**

**le pipeline de données complet pour entraîner BERT avec PyTorch**
"""

class TweetDataset(Dataset):   # transformer tes données en format utilisable par le modèle
    def __init__(self, texts, labels, tokenizer, max_len=128):
        self.texts   = texts
        self.labels  = labels
        self.tok     = tokenizer
        self.max_len = max_len

    def __len__(self):
        return len(self.texts)

    def __getitem__(self, idx):
        enc = self.tok(                # Convertit le texte en : input_ids (tokens numériques) et attention_mask (0 = padding, 1 = vrai token)
            str(self.texts[idx]),
            max_length=self.max_len,
            padding="max_length",
            truncation=True,
            return_tensors="pt"
        )
        return {
            "input_ids":      enc["input_ids"].squeeze(),
            "attention_mask": enc["attention_mask"].squeeze(),
            "label":          torch.tensor(self.labels[idx], dtype=torch.long)
        }

BATCH_SIZE = 32  # GPU Colab T4 supporte 32 sans problème

train_ds = TweetDataset(X_train, y_train, tokenizer)
test_ds  = TweetDataset(X_test,  y_test,  tokenizer)

train_loader = DataLoader(train_ds, batch_size=BATCH_SIZE, shuffle=True,    # Regroupe les données en batches automatiquement
                          num_workers=2, pin_memory=True)
test_loader  = DataLoader(test_ds,  batch_size=BATCH_SIZE,
                          num_workers=2, pin_memory=True)

print(f"Batches train : {len(train_loader)} | Batches test : {len(test_loader)}")



"""# **5. Modèle + gestion du déséquilibre**

Puisque le dataset est déséquilibré , le modèle va apprendre à ignorer la classe 0 parce qu'elle est rare — il peut atteindre 85% d'accuracy en prédisant presque toujours "offensive". C'est le problème classique de déséquilibre.

`compute_class_weight("balanced", ...)` calcule automatiquement un poids inversement proportionnel à la fréquence de chaque classe :
`poids = total_exemples / (nb_classes × nb_exemples_de_cette_classe)`

- Donc le modele est  forcé d'apprendre la classe rare

![class_weights_viz.svg](data:image/svg+xml;base64,)

- class_weights → corrige le déséquilibre
- CrossEntropyLoss(weight=...) → applique cette correction
- AutoModelForSequenceClassification → charge BERTweet prêt à classifier
- num_labels=3 → adapte le modèle à ton problème
"""

# Poids pour compenser le déséquilibre (classe 0 = seulement 810 exemples)
class_weights = compute_class_weight(
    class_weight="balanced",
    classes=np.array([0, 1, 2]),
    y=y_train
)
weights = torch.tensor(class_weights, dtype=torch.float).to(device)
print(f"Class weights : {class_weights.round(3)}")
# → classe 0 (hate) aura le poids le plus fort

loss_fn = torch.nn.CrossEntropyLoss(weight=weights)     # Ces poids sont ensuite passés à la loss function

# Chargement BERTweet
model = AutoModelForSequenceClassification.from_pretrained(
    MODEL_NAME,
    num_labels=3,
    ignore_mismatched_sizes=True
).to(device)

print(f"Paramètres : {sum(p.numel() for p in model.parameters()):,}")

"""# **8 — Optimizer + Scheduler (bonne pratique pour BERT)**"""

EPOCHS    = 4
LR        = 2e-5
total_steps = len(train_loader) * EPOCHS
warmup_steps = int(0.1 * total_steps)   # 10% warmup

optimizer = AdamW(model.parameters(), lr=LR, weight_decay=0.01)

scheduler = get_linear_schedule_with_warmup(
    optimizer,
    num_warmup_steps=warmup_steps,
    num_training_steps=total_steps
)

print(f"Total steps : {total_steps} | Warmup : {warmup_steps}")

"""- 267 batches = nombre de mini-groupes par epoch
- 4 epochs = nombre de répétitions sur les données
- 1068 steps = modèle sera mis à jour 1068 fois pendant l’entraînement
- 107 warmup = démarrage progressif de l’apprentissage

AdamW met à jour les poids du modèle après chaque batch. Les deux paramètres importants :

- lr=2e-5 → le pas d'apprentissage. Très petit exprès — BERT est déjà pré-entraîné, on ne veut que l'affiner doucement sans "oublier" ce qu'il sait déjà

- weight_decay=0.01 → une pénalité sur les grands poids pour éviter l'overfitting

![lr_schedule_warmup.svg](data:image/svg+xml;base64,)

`scheduler = get_linear_schedule_with_warmup(...)`

Au lieu de garder lr=2e-5 fixe pendant tout l'entraînement, le scheduler fait varier le learning rate

- Phase warmup (10% des steps) → le LR monte progressivement de 0 à 2e-5. Ça évite de faire des mises à jour trop brutales au début quand le modèle est encore "désorienté"
- Phase décroissance (90% restants) → le LR redescend doucement jusqu'à 0. Le modèle affine de plus en plus finement

# **6. Boucle d'entraînement**
"""

history = {"train_loss": [], "val_f1": []}

for epoch in range(EPOCHS):
    # ── TRAIN ──
    model.train()
    total_loss = 0

    for batch in train_loader:
        ids   = batch["input_ids"].to(device)
        mask  = batch["attention_mask"].to(device)
        lbls  = batch["label"].to(device)

        optimizer.zero_grad()
        outputs = model(input_ids=ids, attention_mask=mask)
        loss = loss_fn(outputs.logits, lbls)
        loss.backward()

        torch.nn.utils.clip_grad_norm_(model.parameters(), max_norm=1.0)
        optimizer.step()
        scheduler.step()
        total_loss += loss.item()

    avg_loss = total_loss / len(train_loader)

    # ── EVAL rapide ──
    model.eval()
    preds_ep, labels_ep = [], []
    with torch.no_grad():
        for batch in test_loader:
            ids  = batch["input_ids"].to(device)
            mask = batch["attention_mask"].to(device)
            out  = model(input_ids=ids, attention_mask=mask)
            preds_ep.extend(torch.argmax(out.logits, dim=1).cpu().numpy())
            labels_ep.extend(batch["label"].numpy())

    f1 = f1_score(labels_ep, preds_ep, average="macro")
    history["train_loss"].append(avg_loss)
    history["val_f1"].append(f1)

    print(f"Epoch {epoch+1}/{EPOCHS} | Loss: {avg_loss:.4f} | F1-macro: {f1:.4f}")

"""À chaque epoch :

- Le modèle apprend (train)
- On calcule la perte (loss)
- On met à jour les poids
- On évalue sur test (F1-score)


1.  La **loss** mesure les erreurs pendant l'entraînement. Elle descend bien à chaque epoch -->  le modèle apprend progressivement sur les données d'entraînement.

2.  Le **F1** mesure les performances sur les données de test

# **7. Évaluation**

- Precision : Parmi les tweets prédits "hate", combien l'étaient vraiment ?

- Recall: Parmi les vrais tweets "hate", combien ont été détectés ?

- Le F1-macro calcule la moyenne du F1 de chaque classe sans tenir compte du déséquilibre --> F1-macro → adapté aux classes déséquilibrées
"""

model.eval()
all_preds, all_labels = [], []

with torch.no_grad():
    for batch in test_loader:
        ids  = batch["input_ids"].to(device)
        mask = batch["attention_mask"].to(device)
        out  = model(input_ids=ids, attention_mask=mask)
        all_preds.extend(torch.argmax(out.logits, dim=1).cpu().numpy())
        all_labels.extend(batch["label"].numpy())

# Rapport
print(classification_report(
    all_labels, all_preds,
    target_names=["hate speech", "offensive", "neither"],
    digits=4
))
print("F1-macro final :", round(f1_score(all_labels, all_preds, average="macro"), 4))

# Confusion matrix
cm = confusion_matrix(all_labels, all_preds)
plt.figure(figsize=(6, 5))
sns.heatmap(cm, annot=True, fmt="d", cmap="Blues",
            xticklabels=["hate", "offensive", "neither"],
            yticklabels=["hate", "offensive", "neither"])
plt.title("Confusion Matrix — BERTweet")
plt.ylabel("Réel") ; plt.xlabel("Prédit")
plt.tight_layout() ; plt.show()

# Courbe loss / F1
fig, (ax1, ax2) = plt.subplots(1, 2, figsize=(10, 4))
ax1.plot(history["train_loss"], marker="o") ; ax1.set_title("Train Loss") ; ax1.set_xlabel("Epoch")
ax2.plot(history["val_f1"],  marker="o", color="green") ; ax2.set_title("F1-macro") ; ax2.set_xlabel("Epoch")
plt.tight_layout() ; plt.show()

